import { Hono } from 'hono';
import { z } from 'zod';

const app = new Hono();

const TeamSchema = z.object({
  name: z.string(),
});

app.post('/team', async (c) => {
  const body = await c.req.json();
  const result = TeamSchema.safeParse(body);

  if (!result.success) {
    return c.json({ error: 'Invalid request body' }, 400);
  }

  const { name } = result.data;
  const teamId = generateTeamId(); // Implement your own logic to generate a unique team ID
  const ownerId = c.req.user.id; // Assuming the user is authenticated and their ID is available

  const newTeam = {
    id: teamId,
    name,
    owner_id: ownerId,
    members: [ownerId],
  };

  // Emit team.created event (Implement your own logic to emit events)
  emitEvent('team.created', newTeam);

  return c.json(newTeam, 201);
});

function generateTeamId(): string {
  // Implement your own logic to generate a unique team ID
  return Math.random().toString(36).substring(7);
}

function emitEvent(event: string, data: any): void {
  // Implement your own logic to emit events (e.g., using a message broker)
  console.log(`Event emitted: ${event}`, data);
}

export default app;

